package src.org.apache.cassandra.service;

public abstract class AbstractWriteResponseHandler implements IWriteResponseHandler { protected final SimpleCondition condition = new SimpleCondition ( ) ; protected final long startTime ; protected final Collection < InetAddress > writeEndpoints ; protected final Multimap < InetAddress , InetAddress > hintedEndpoints ; protected final ConsistencyLevel consistencyLevel ; protected AbstractWriteResponseHandler ( Collection < InetAddress > writeEndpoints , Multimap < InetAddress , InetAddress > hintedEndpoints , ConsistencyLevel consistencyLevel ) { startTime = System . currentTimeMillis ( ) ; this . consistencyLevel = consistencyLevel ; this . hintedEndpoints = hintedEndpoints ; this . writeEndpoints = writeEndpoints ; } public void get ( ) throws TimeoutException { long timeout = DatabaseDescriptor . getRpcTimeout ( ) - ( System . currentTimeMillis ( ) - startTime ) ; boolean success ; try { success = condition . await ( timeout , TimeUnit . MILLISECONDS ) ; } catch ( InterruptedException ex ) { throw new AssertionError ( ex ) ; } if ( ! success ) { throw new TimeoutException ( ) ; } } public abstract void response ( Message msg ) ; public abstract void assureSufficientLiveNodes ( ) throws UnavailableException ; }